import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Login from './pages/Login';
import Groups from './pages/Groups';
import GroupDetails from './pages/GroupDetails';
import MyGroups from './pages/MyGroups';  // Importation du composant MyGroups

// Exemple de données fictives pour l'utilisateur connecté
const currentUser = {
    id: 1,
    name: 'Antoine',
    groups: [
        { id: 1, name: 'Group 1', image: 'group1.jpg', members: ['Antoine', 'Alice', 'Bob'] },
        { id: 2, name: 'Group 2', image: 'group2.jpg', members: ['Antoine', 'Charlie'] }
    ]
};

export default function App() {
    return (
        <Router>
            <Routes>
                {/* Route racine */}
                <Route path="/" element={<Login />} />

                {/* Route groupes avec sous-route */}
                <Route path="/groups">
                    <Route index element={<Groups />} />
                    <Route path=":groupId" element={<GroupDetails />} />
                </Route>

                {/* Route "Mes Groupes" */}
                <Route path="/my-groups" element={<MyGroups currentUser={currentUser} />} />

                {/* Redirection pour les routes inconnues */}
                <Route path="*" element={<Login />} />
            </Routes>
        </Router>
    );
}
